SELECT {{.Product}}, AVG_REPLENISHMENT_CYCLE as Sales_Frequency
FROM (

SELECT {{.Product}}, round(AVG(REPLENISHMENT_CYCLE)) AS AVG_REPLENISHMENT_CYCLE, count(*) AS COUNTER
FROM (

SELECT *, 
DATE_DIFF(PARSE_DATE( '%Y-%m-%d', substring({{.Date}},1,10) ),PARSE_DATE( '%Y-%m-%d', substring(LAG_DATE,1,10) ), DAY) 
AS REPLENISHMENT_CYCLE
FROM ( 
select *, LAG({{.Date}})
   OVER (PARTITION BY {{.Area_Hierarchy_3}}, {{.Product}} ORDER BY {{.Date}} ASC) AS LAG_DATE
from (
 
SELECT {{.Area_Hierarchy_3}}, {{.Product}}, {{.Value}}, {{.Qty}}, {{.Date}}
 
from KEYSTONE_{{.company_name}}.SALES_VIEW

where 
{{.Area_Hierarchy_3}} = {{.display_value}} 
and {{.Product_Hierarchy_2}} = JSON_VALUE({{.level_filter}}, '$.{{.Product_Hierarchy_2}}')
AND  {{.Overall_Hierarchy_1}} = JSON_VALUE({{.level_filter}}, '$.{{.Overall_Hierarchy_1}}')

and {{.Qty}} > 0
and
extract(year from PARSE_DATE( '%Y-%m-%d', substring({{.Date}},1,10) )) >= 2021

ORDER BY {{.Area_Hierarchy_3}}, {{.Date}} ASC
)
ORDER BY {{.Area_Hierarchy_3}}, {{.Product}}, {{.Date}}

)
)
GROUP BY {{.Product}}
ORDER BY AVG_REPLENISHMENT_CYCLE DESC
) 
where AVG_REPLENISHMENT_CYCLE is not null
and {{.Product}} is not null

